App [
    View [ fill = #2A3A4A, onClick() { classroot.select() } ]
]

App [ fill = #0B141B,
    header: View [ width = { app.hostWidth }, opacity = { 1 - app.scrollY / 200 } ],
]

App [
    View [ textColor = #CAD0EC, fontSize = 14,
      Text [ text = "inherits the panel's style" ]
    ]
]

App [
    Markdown [ width = { parent.width }, text = { :body } ]
]

App [
    preview: HTML [ width = { parent.width }, height = 300, slot = "run:demo" ]
]

App [
    View [ layout: SimpleLayout [ axis = y, spacing = 10 ],
        Text [ text = "one" ],
        Text [ text = "two" ],
    ]
]

App [
    View [ width = { parent.width }, layout: WrappingLayout [ spacing = 8, lineSpacing = 8 ] ]
]

App [ fill = #0B141B, textColor = whitesmoke,
    fontFamily = ["system-ui", "sans-serif"], fontSize = 15,
    ]

App [ fontFamily = ["Helvetica Neue", "Geneva", "sans-serif"], fontSize = 9,
      fontWeight = bold, textColor = #FFFFFF, zip: string = "94110",

    // none of these Texts repeat the family, size, weight, or colour — they
    // inherit the App's, and would inherit any nearer container's instead

    topBar: View [
        title: Text [ text = "Rain or Shine?" ],
        zip:   Text [ text = { app.zip }, textColor = #CAD0EC ],   // overrides just the colour
        ],
    ]

App [
    moreData: View [ x = 15,
        layout: SimpleLayout [ axis = x, spacing = -10 ],   // two columns side by side

        labels: View [ layout: SimpleLayout [ axis = y, spacing = 1 ],
            Text [ text = "Humidity:" ],
            Text [ text = "Wind:" ],
            ],
        fields: View [ layout: SimpleLayout [ axis = y, spacing = 1 ],
            Text [ text = "62%" ],
            Text [ text = "8 mph" ],
            ],
        ]
]

App [
    contact: Dataset { { "person": { "name": "Ada", "zip": "94110" } } },
    form: View [ datapath = { app.contact.value.person },
        name: TextInput [ y = 20, text <-> :name ],          // shows :name AND commits edits back to it
        zip:  TextInput [ y = 80, text <-> :zip,             // a domain rule beyond the type
              validate(v) { return /^[0-9]{5}$/.test(v) ? null : "must be 5 digits" } ],
        note: Text [ y = 120, textColor = #cc5b47, text = { app.form.zip.error } ],  // the field owns its error
        echo: Text [ y = 160, text = { "saved → " + app.contact.value.person.name + " / " + app.contact.value.person.zip } ],
    ],
]

App [
    reveal: AnimatorGroup [ process = simultaneous,
        Animator [ attribute = opacity, to = 1, duration = 200 ],
        Animator [ attribute = y,       to = 20, duration = 200 ],
        ],
]

App [
    Text [ x = 24, y = 24, fontSize = { app.width < 700 ? 44 : 60 }, text = "Responsive" ]
]

App [
    zipField: TextInput [ x = 84, y = 4, width = 96, placeholder = "Zip code",
        onInput(v) { app.zip = v },              // each keystroke — v is the new text
        onEnter()  { app.weather.fetch() },      // Enter, on a single-line field — submit
        ]
]
